// ============================================================================
//  Build the Cohere /v2/chat request body from the sorted + deduped comments
// ============================================================================
//
//  Upstream: Sort by diggCount desc → Remove Duplicates by uniqueId (keeps
//  first occurrence, which — after the sort — is the highest-diggCount
//  comment per unique commenter).
//
//  Input  : one item per unique commenter
//  Output : single item with three fields:
//             - comments         : compact array of { username, text, likes,
//                                    replies, video_url } per prospect
//             - count            : number of unique commenters
//             - cohere_body_json : full Cohere /v2/chat request body as a
//                                  JSON string, ready for the HTTP Request
// ============================================================================

// Reshape each item to the compact form the LLM expects
const comments = [];
for (const item of $input.all()) {
  const c = item.json;
  const username = (c.uniqueId || '').toString().trim();
  if (!username) continue;
  comments.push({
    username,
    text: (c.text || '').toString(),
    likes: Number(c.diggCount || 0),
    replies: Number(c.replyCommentTotal || 0),
    video_url: (c.videoWebUrl || '').toString(),
  });
}

// Pull the topic/target/model/shortlist size from the Config node
const config = $('Config').first().json;
const shortlistSize = Number(config.shortlist_size || 15);
const llmModel = config.llm_model || 'command-a-03-2025';

// ---- Auto-detect topic and target if set to "auto" -----------------------
// When the reader pastes a new video URL without customizing topic/target,
// the code auto-infers context from the first 15 comments. This means the
// workflow works for ANY niche out of the box — real estate, fitness, SaaS,
// dropshipping, whatever — without manual prompt editing.
let topic = (config.topic || '').toString().trim();
if (!topic || topic.toLowerCase() === 'auto') {
  const sampleTexts = comments.slice(0, 15).map(c => c.text).join(' | ');
  topic = 'a TikTok video. Here is a sample of the comments to help you understand the topic and audience: ' + sampleTexts.substring(0, 500);
}

let target = (config.target || '').toString().trim();
if (!target || target.toLowerCase() === 'auto') {
  target = 'anyone who appears to be running, starting, or actively trying to grow a business — regardless of industry or niche. Look for signals of real business activity (stores, services, products, clients) rather than passive interest.';
}

const systemPrompt = 'You are a B2B prospect-qualification analyst helping a sales team find high-intent leads inside a TikTok comment section.\n\nContext:\n- Source video topic: {{TOPIC}}\n- Target buyer: {{TARGET}}\n\nYour task:\nFrom the JSON array of TikTok comments (each has: username, text, likes, replies), identify up to {{SHORTLIST_SIZE}} commenters who look like real prospects for cold outreach. Rank them by buying intent — how close each commenter is to needing and buying a product or service today.\n\nSTRICT RANKING RUBRIC — use these exact definitions:\n\n- high — The commenter is clearly running a real business RIGHT NOW. Signals: they mention their own store/shop/service/product (e.g., "I have a TikTok shop", "my Shopify store", "my embroidery business", "I\'m a realtor"), OR their username explicitly references a business or profession (e.g., "@something_realtor", "@shopname", "@agencyname", "*_biz"), OR they describe an active, specific business pain point they are trying to solve. These are the prospects you would email first.\n\n- medium — The commenter has relevant signals but weaker ones. They describe trying or planning to start a business, OR ask a substantive how-to question about running/scaling a business, OR their username is business-adjacent but ambiguous.\n\n- low — The commenter has only mild signals: general business curiosity, personal development talk, or weak engagement with the topic.\n\nSkip entirely: generic reactions, fan messages, emoji-only comments, skeptics, scam accounts (Telegram/WhatsApp/crypto in the comment), people who say they can\'t use the product in their country, people venting about debt with no business context.\n\nTie-breaker between two similar comments: prefer the one with higher likes and more replies.\n\nReturn EXACTLY one JSON object with a `prospects` field containing up to {{SHORTLIST_SIZE}} ranked objects. Each object has:\n- username: the TikTok handle, WITHOUT the @ prefix. Must appear verbatim in the input array.\n- comment_excerpt: a short verbatim quote (≤140 chars) from their actual comment\n- why_prospect: one sentence explaining the specific signal that made them a prospect\n- priority: "high", "medium", or "low"\n\nOrder the array by priority (highs first). Favor quality over quantity.'
  .replaceAll('{{TOPIC}}', topic)
  .replaceAll('{{TARGET}}', target)
  .replaceAll('{{SHORTLIST_SIZE}}', String(shortlistSize));

const prospectSchema = {
  type: 'object',
  properties: {
    prospects: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          username:        { type: 'string' },
          comment_excerpt: { type: 'string' },
          why_prospect:    { type: 'string' },
          priority:        { type: 'string', enum: ['high', 'medium', 'low'] },
        },
        required: ['username', 'comment_excerpt', 'why_prospect', 'priority'],
      },
    },
  },
  required: ['prospects'],
};

const cohereBody = {
  model: llmModel,
  messages: [
    { role: 'system', content: systemPrompt },
    {
      role: 'user',
      content:
        'Here is the full JSON array of TikTok comments. Return the ranked shortlist now.\n\n' +
        JSON.stringify(comments),
    },
  ],
  response_format: { type: 'json_object', json_schema: prospectSchema },
  temperature: 0.1,
  max_tokens: 4000,
};

return [
  {
    json: {
      comments,
      count: comments.length,
      cohere_body_json: JSON.stringify(cohereBody),
    },
  },
];

// ============================================================================
//  Parse the Cohere response and extract the ranked prospect shortlist
// ============================================================================
//
//  Input  : single item — the raw Cohere /v2/chat response
//  Output : single item with two fields:
//             - prospects : full ranked objects from Cohere (with priority,
//                           why_prospect, comment_excerpt, username)
//             - usernames : flat array of usernames ready to feed into the
//                           Profile Scraper (stripped of any '@' prefix)
// ============================================================================

const response = $input.first().json;

// The Cohere response has message.content as a list of blocks. Grab text
// blocks only (a future model could emit thinking blocks too).
const contentBlocks = (response && response.message && response.message.content) || [];
let rawText = '';
for (const block of contentBlocks) {
  if (block && block.type === 'text' && typeof block.text === 'string') {
    rawText += block.text;
  }
}

if (!rawText) {
  throw new Error('Cohere response contained no text content blocks');
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  throw new Error('Failed to parse Cohere response as JSON: ' + e.message);
}

const prospects = (parsed && parsed.prospects) || [];
const usernames = prospects
  .map((p) => (p.username || '').toString().replace(/^@+/, '').trim())
  .filter(Boolean);

if (usernames.length === 0) {
  throw new Error('Cohere returned zero prospects — nothing to enrich');
}

return [
  {
    json: {
      prospects,
      usernames,
      shortlist_count: usernames.length,
    },
  },
];

// ============================================================================
//  Join the LLM rankings + original comments + enriched profiles into one
//  unified row per prospect
// ============================================================================
//
//  Data sources (via cross-node references):
//    1. Current input          : Profile Scraper output (one row per video,
//                                 with nested authorMeta per profile)
//    2. Extract Shortlist node : Cohere's ranked prospects (priority, reason)
//    3. Build Cohere Request   : the deduped comments array with original text
//
//  Output : one item per prospect, ordered by priority (high → medium → low)
// ============================================================================

// Build a username -> authorMeta lookup from the Profile Scraper items
const profilesByUsername = {};
for (const item of $input.all()) {
  const author = (item.json && item.json.authorMeta) || {};
  const name = (author.name || '').toString().trim().toLowerCase();
  if (!name) continue;
  if (!profilesByUsername[name]) {
    profilesByUsername[name] = author;
  }
}

// Pull the rankings from the Extract Shortlist node
const extractOutput = $('Extract Shortlist').first().json;
const rankings = (extractOutput && extractOutput.prospects) || [];

// Pull the deduped comments from the Build Cohere Request node
const buildOutput = $('Build Cohere Request').first().json;
const dedupedComments = (buildOutput && buildOutput.comments) || [];
const commentsByUsername = {};
for (const c of dedupedComments) {
  if (c && c.username) {
    commentsByUsername[c.username.toLowerCase()] = c;
  }
}

// Sort rankings: high → medium → low
const priorityOrder = { high: 0, medium: 1, low: 2 };
const sorted = [...rankings].sort(
  (a, b) => (priorityOrder[a.priority] ?? 99) - (priorityOrder[b.priority] ?? 99)
);

const output = [];
for (const r of sorted) {
  const username = (r.username || '').toString().replace(/^@+/, '').trim();
  if (!username) continue;
  const key = username.toLowerCase();

  const profile = profilesByUsername[key] || {};
  const comment = commentsByUsername[key] || {};

  // bioLink is sometimes a string, sometimes a dict { link: "..." }
  let bioLink = profile.bioLink;
  if (bioLink && typeof bioLink === 'object') {
    bioLink = bioLink.link || '';
  }

  output.push({
    json: {
      priority:       r.priority || 'low',
      username:       username,
      followers:      Number(profile.fans || 0),
      is_seller:      Boolean(profile.ttSeller),
      is_verified:    Boolean(profile.verified),
      is_private:     Boolean(profile.privateAccount),
      bio:            (profile.signature || '').toString(),
      bio_link:       (bioLink || '').toString(),
      profile_url:    (profile.profileUrl || `https://www.tiktok.com/@${username}`).toString(),
      comment_text:   (comment.text || r.comment_excerpt || '').toString(),
      comment_likes:  Number(comment.likes || 0),
      comment_replies: Number(comment.replies || 0),
      why_prospect:   (r.why_prospect || '').toString(),
      video_url:      (comment.video_url || '').toString(),
    },
  });
}

return output;
